const validViews=['dashboard','epg','viewers','channels','status','recordings','clients','system','settings'];
const initialView=location.hash.slice(1);
const savedChannelSort=localStorage.getItem('channelSort');
const validRecordingSections=['upcoming','conflicts','finished','failed','removed','autorecs','timerecs'];
const savedRecordingSection=localStorage.getItem('recordingSection');
const state={view:validViews.includes(initialView)?initialView:'dashboard',data:null,resources:null,theme:localStorage.getItem('theme')||'system',timer:null,historyMode:'detail',epgMode:localStorage.getItem('epgMode')||'now',epgChannel:'',channelSort:['number','name'].includes(savedChannelSort)?savedChannelSort:'number',recordingSection:validRecordingSections.includes(savedRecordingSection)?savedRecordingSection:'upcoming'};
const scheduleState={eventId:'',configUuid:'',channelUuid:'',channelQuery:'',events:[],profiles:[],channels:[]};
const ruleState={mode:'autorec',uuid:'',enabled:true,channel:'',channelQuery:'',configUuid:'',data:null};
const recordingRuleEntries=new Map();
let cancelRecordingUuid='',disconnectClientId=0;
const $=s=>document.querySelector(s);const view=$('#view');
const titles={dashboard:['实时状态','概览'],epg:['正在播出与未来节目','节目单'],viewers:['用户与频道','观看记录'],channels:['TvHeadend 频道库','频道'],status:['调谐器','信号'],recordings:['计划与历史','录像'],clients:['实时连接与受控操作','客户端管理'],system:['TvHeadend API 快照','系统资源'],settings:['本地持久化配置','连接设置']};
const esc=v=>String(v??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const duration=s=>{s=Math.max(0,Number(s)||0);if(s<60)return`${s} 秒`;if(s<3600)return`${Math.floor(s/60)} 分钟`;return`${Math.floor(s/3600)} 小时 ${Math.floor(s%3600/60)} 分`};
const date=t=>t?new Date(t*1000).toLocaleString('zh-CN',{month:'2-digit',day:'2-digit',hour:'2-digit',minute:'2-digit'}):'—';
const compactDuration=s=>{s=Math.max(0,Number(s)||0);if(s<60)return`${s}秒`;if(s<3600)return`${Math.floor(s/60)}分钟`;return`${Math.floor(s/3600)}小时${Math.floor(s%3600/60)}分钟`};
const pad2=n=>String(n).padStart(2,'0');
const mdTime=t=>{const d=new Date(t*1000);return`${pad2(d.getMonth()+1)}/${pad2(d.getDate())} ${pad2(d.getHours())}:${pad2(d.getMinutes())}`};
const epgRange=(start,stop)=>{if(!start||!stop)return'—';const a=new Date(start*1000),b=new Date(stop*1000),same=a.getFullYear()===b.getFullYear()&&a.getMonth()===b.getMonth()&&a.getDate()===b.getDate();return`${mdTime(start)} - ${same?`${pad2(b.getHours())}:${pad2(b.getMinutes())}`:mdTime(stop)}`};
const fullDate=t=>{if(!t)return['—',''];const d=new Date(t*1000);return[d.toLocaleDateString('zh-CN',{year:'numeric',month:'2-digit',day:'2-digit'}).replaceAll('/','-'),d.toLocaleTimeString('zh-CN',{hour:'2-digit',minute:'2-digit'})]};
const localized=v=>{if(v&&typeof v==='object')return v.chi||v.zho||v.zh||v.eng||Object.values(v)[0]||'';return v??''};
const titlePair=v=>v&&typeof v==='object'?[v.chi||v.zho||v.zh||v.eng||Object.values(v)[0]||'',v.eng&&v.eng!==(v.chi||v.zho||v.zh)?v.eng:'']:[v??'',''];
const reducedMotion=()=>matchMedia('(prefers-reduced-motion: reduce)').matches;
const channelCollator=new Intl.Collator('zh-CN',{numeric:true,sensitivity:'base'});
let channelNameObserver=null,channelNameVisibilityObserver=null;
function sortedChannels(items,mode=state.channelSort){return [...items].sort((a,b)=>{if(mode==='name')return channelCollator.compare(a.name||'',b.name||'')||channelCollator.compare(String(a.number||''),String(b.number||''));const an=String(a.number||'').trim(),bn=String(b.number||'').trim();if(Boolean(an)!==Boolean(bn))return an?-1:1;return channelCollator.compare(an,bn)||channelCollator.compare(a.name||'',b.name||'')})}
function activateChannelNameScroll(root){channelNameObserver?.disconnect();channelNameVisibilityObserver?.disconnect();const update=()=>{const boxes=[...root.querySelectorAll('.channel-name-viewport')];boxes.forEach(box=>{const text=box.firstElementChild;box.classList.remove('scrolling','scroll-active');box.style.removeProperty('--channel-name-offset');box.style.removeProperty('--channel-name-duration');const overflow=Math.ceil(text.scrollWidth-box.clientWidth);if(overflow>2&&!reducedMotion()){box.style.setProperty('--channel-name-offset',`-${overflow}px`);box.style.setProperty('--channel-name-duration',`${Math.min(14,Math.max(5,5+overflow/22))}s`);box.classList.add('scrolling')}});channelNameVisibilityObserver?.disconnect();if('IntersectionObserver'in window){channelNameVisibilityObserver=new IntersectionObserver(entries=>entries.forEach(entry=>entry.target.classList.toggle('scroll-active',entry.isIntersecting)),{rootMargin:'40px 0px'});boxes.filter(box=>box.classList.contains('scrolling')).forEach(box=>channelNameVisibilityObserver.observe(box))}else boxes.forEach(box=>box.classList.toggle('scroll-active',box.classList.contains('scrolling')))};requestAnimationFrame(update);if('ResizeObserver'in window){channelNameObserver=new ResizeObserver(update);channelNameObserver.observe(root)}}
new MutationObserver(()=>{if(!$('#channelGrid')&&(channelNameObserver||channelNameVisibilityObserver)){channelNameObserver?.disconnect();channelNameVisibilityObserver?.disconnect();channelNameObserver=null;channelNameVisibilityObserver=null}}).observe(view,{childList:true});
const delay=ms=>new Promise(resolve=>setTimeout(resolve,ms));
const settleTransition=(started,minimum=280)=>reducedMotion()?Promise.resolve():delay(Math.max(0,minimum-(performance.now()-started)));
function finishRefreshCycle(button){const icon=button.querySelector('svg');if(reducedMotion()||!icon||!button.classList.contains('refreshing'))return Promise.resolve();return new Promise(resolve=>{let timer;const done=()=>{clearTimeout(timer);icon.removeEventListener('animationiteration',done);resolve()};icon.addEventListener('animationiteration',done,{once:true});timer=setTimeout(done,900)})}
let viewAnimationHandler=null;
function stopViewAnimation(){if(viewAnimationHandler)view.removeEventListener('animationend',viewAnimationHandler);viewAnimationHandler=null;view.classList.remove('view-enter','view-refresh-enter','view-leave','view-pending')}
function animateView(kind='view-enter'){stopViewAnimation();void view.offsetWidth;view.classList.add(kind);viewAnimationHandler=event=>{if(event.target!==view)return;view.classList.remove(kind);view.removeEventListener('animationend',viewAnimationHandler);viewAnimationHandler=null};view.addEventListener('animationend',viewAnimationHandler)}
const tvIcon=()=>'<svg viewBox="0 0 24 24" aria-hidden="true"><path d="M7 2.8 12 7l5-4.2 1.3 1.5L15.1 7H18a3 3 0 0 1 3 3v8a3 3 0 0 1-3 3H6a3 3 0 0 1-3-3v-8a3 3 0 0 1 3-3h2.9L5.7 4.3 7 2.8ZM6 9a1 1 0 0 0-1 1v8a1 1 0 0 0 1 1h12a1 1 0 0 0 1-1v-8a1 1 0 0 0-1-1H6Z"/></svg>';
async function api(url,opt){let r;try{r=await fetch(url,opt)}catch(error){throw Error(navigator.onLine?'无法连接 TvHeadend Manager':'当前离线，等待重新连接')}const j=await r.json().catch(()=>({error:`HTTP ${r.status}`}));if(!r.ok||j.ok===false){if(r.status===401&&!url.startsWith('/api/auth/'))showLogin();if(r.status===404&&url==='/api/preferences')throw Error('当前服务端仍是旧版本，请重启 TvHeadend Manager 后再保存');throw Error(j.error||`HTTP ${r.status}`)}return j}
function applyTheme(){const dark=state.theme==='dark'||(state.theme==='system'&&matchMedia('(prefers-color-scheme:dark)').matches);document.documentElement.dataset.theme=dark?'dark':'light';const themeColor=$('meta[name="theme-color"]');if(themeColor)themeColor.content=dark?'#111318':'#f3f2f8';const railTheme=$('#themeBtn span');if(railTheme)railTheme.textContent={system:'跟随系统',light:'浅色模式',dark:'深色模式'}[state.theme];document.querySelectorAll('[data-theme-choice]').forEach(b=>b.classList.toggle('active',b.dataset.themeChoice===state.theme))}
function empty(text='暂无数据'){return`<div class="empty">${esc(text)}</div>`}
function progress(start,stop,now){const p=Math.max(0,Math.min(100,(now-start)/(stop-start)*100||0));return`<div class="progress"><i style="width:${p}%"></i></div>`}
function liveRows(items){return items.length?`<div class="list">${items.map(x=>{const grab=String(x.channel_name||'').toLowerCase()==='epggrab';const user=grab?'EPG 搜刮器':x.username;const sub=grab?'epggrab':[x.channel_name,x.client].filter(v=>v&&v!=='未知客户端').join(' · ');return`<div class="list-row"><div class="avatar">${grab?'EPG':esc((user||'?')[0].toUpperCase())}</div><div><strong>${esc(user)}</strong><small>${esc(sub)}</small></div><span class="badge live">${duration(x.duration_seconds)}</span></div>`}).join('')}</div>`:empty('目前没有用户观看')}
function iconMarkup(x){return x.channel_uuid?`<img class="channel-icon epg-icon" data-fallback src="/api/channels/${encodeURIComponent(x.channel_uuid)}/icon" alt="">`:`<div class="channel-icon tv-fallback">${tvIcon()}</div>`}
function bindIconFallback(root=document){root.querySelectorAll('.channel-icon[data-fallback]').forEach(img=>img.addEventListener('error',()=>{const f=document.createElement('div');f.className='channel-icon tv-fallback';f.innerHTML=tvIcon();img.replaceWith(f)},{once:true}))}
function epgRows(items,now){return items.length?`<div class="list">${items.slice(0,12).map(x=>`<div class="list-row">${iconMarkup(x)}<div><strong>${esc(localized(x.title))}</strong><small>${esc(x.channel_name)} · ${epgRange(x.start,x.stop)}</small>${progress(x.start,x.stop,now)}</div><span></span></div>`).join('')}</div>`:empty('TvHeadend 暂无当前 EPG')}
function epgCenterRows(items,serverTime){return items.length?`<div class="epg-center-list">${items.map(x=>{const live=x.start<=serverTime&&x.stop>serverTime,future=x.start>serverTime,details=localized(x.summary||x.description||x.subtitle),flags=[x.is_new?'首播':'',x.is_hd?'高清':'',x.is_subtitled?'字幕':''].filter(Boolean);return`<article class="epg-center-row">${iconMarkup(x)}<div class="epg-center-copy"><strong>${esc(localized(x.title)||'无标题')}</strong><small>${esc(x.channel_name)} · ${epgRange(x.start,x.stop)}</small>${details?`<p>${esc(details)}</p>`:''}${live?progress(x.start,x.stop,serverTime):''}</div><div class="epg-center-actions">${flags.map(flag=>`<span class="badge">${flag}</span>`).join('')}${live?'<span class="badge live">正在播出</span>':future?`<button class="tonal epg-record" data-event="${esc(x.event_id)}" data-channel="${esc(x.channel_uuid)}">安排录像</button>`:''}</div></article>`}).join('')}</div>`:empty('这个范围内暂无节目')}
async function loadDashboard(){const d=await api('/api/dashboard');state.data=d;setUpdated(d.lastSync);const s=d.stats;view.innerHTML=`<div class="stats"><div class="stat"><span>正在观看</span><strong>${s.viewers}</strong></div><div class="stat"><span>可用频道</span><strong>${s.channels}</strong></div><div class="stat"><span>活跃输入</span><strong>${s.active_inputs}</strong></div><div class="stat"><span>今日观看</span><strong>${compactDuration(s.watch_seconds)}</strong></div></div><div class="grid-2"><div class="card"><div class="card-head"><h2>当前观看</h2><span class="badge live">LIVE</span></div>${liveRows(d.live)}</div><div class="card"><div class="card-head"><h2>正在播出</h2><span class="badge">${d.currentEpg.length} 个节目</span></div>${epgRows(d.currentEpg,d.serverTime)}</div></div>`;bindIconFallback(view)}
async function loadEpg(){const d=await api('/api/epg');const render=items=>{$('#epgList').innerHTML=epgRows(items,Math.floor(Date.now()/1000));bindIconFallback($('#epgList'))};view.innerHTML=`<input class="search" id="epgSearch" placeholder="搜索节目或频道…"><div class="card" id="epgList"></div>`;render(d.entries);let timer;$('#epgSearch').oninput=e=>{clearTimeout(timer);timer=setTimeout(async()=>{const x=await api('/api/epg?q='+encodeURIComponent(e.target.value));render(x.entries)},250)}}
async function loadViewers(){const d=await api('/api/history');const render=()=>{document.querySelectorAll('.segmented button').forEach(b=>b.classList.toggle('active',b.dataset.mode===state.historyMode));if(state.historyMode==='detail'){$('#historyBody').innerHTML=`<div class="table-wrap"><table class="history-table history-detail-table"><thead><tr><th>用户</th><th>频道</th><th>来源 IP</th><th>客户端 / 协议</th><th>开始时间</th><th>本次观看</th><th>状态</th></tr></thead><tbody>${d.entries.map(x=>{const ip=x.client_ip||'未知 IP',client=x.client||'未知客户端';return`<tr><td>${esc(x.username)}</td><td>${esc(x.channel_name)}</td><td><span class="history-source" title="${esc(ip)}">${esc(ip)}</span></td><td><span class="history-source" title="${esc(client)}">${esc(client)}</span></td><td>${date(x.started_at)}</td><td>${duration(x.duration_seconds)}</td><td><span class="badge ${x.active?'live':''}">${x.active?'正在观看':'已结束'}</span></td></tr>`}).join('')}</tbody></table>${d.entries.length?'':empty()}</div>`}else{const a=d.summary||[];$('#historyBody').innerHTML=`<div class="table-wrap"><table class="history-table"><thead><tr><th>用户</th><th>频道</th><th>观看次数</th><th>累计观看</th></tr></thead><tbody>${a.map(x=>`<tr><td>${esc(x.username)}</td><td>${esc(x.channel_name)}</td><td>${x.session_count} 次</td><td><strong>${duration(x.total_seconds)}</strong></td></tr>`).join('')}</tbody></table>${a.length?'':empty()}</div>`}};view.innerHTML=`<div class="view-toolbar"><div class="segmented"><button data-mode="detail">单次时长</button><button data-mode="total">累计时长</button></div></div><div id="historyBody"></div>`;document.querySelectorAll('.segmented button').forEach(b=>b.onclick=()=>{state.historyMode=b.dataset.mode;render()});render()}
async function loadChannels(){const d=await api('/api/channels'),labels={number:'频道号',name:'频道名称'};const render=()=>{const query=$('#channelSearch').value.trim().toLocaleLowerCase('zh-CN'),items=d.entries.filter(x=>!query||String(x.name||'').toLocaleLowerCase('zh-CN').includes(query)||String(x.number||'').includes(query));$('#channelGrid').innerHTML=channelCards(sortedChannels(items));bindIconFallback($('#channelGrid'));activateChannelNameScroll($('#channelGrid'))};const renderSort=()=>{$('#channelSortLabel').textContent=labels[state.channelSort];$('#channelSortMenu').innerHTML=Object.entries(labels).map(([key,label])=>`<button type="button" data-channel-sort="${key}" class="${key===state.channelSort?'selected':''}"><span>${label}</span><i>${key===state.channelSort?'✓':''}</i></button>`).join('');$('#channelSortMenu').querySelectorAll('[data-channel-sort]').forEach(button=>button.onclick=()=>{state.channelSort=button.dataset.channelSort;localStorage.setItem('channelSort',state.channelSort);$('#channelSort').removeAttribute('open');renderSort();render()})};view.innerHTML=`<div class="channel-toolbar"><input class="search" id="channelSearch" placeholder="搜索频道或频道号…"><details class="md-select channel-sort" id="channelSort"><summary><span>排序</span><strong id="channelSortLabel"></strong><i></i></summary><div class="md-select-menu" id="channelSortMenu"></div></details></div><div class="channels" id="channelGrid"></div>`;renderSort();render();$('#channelSearch').oninput=render}
function channelCards(a){return a.length?a.map(x=>`<article class="channel-card"><img class="channel-icon" data-fallback src="/api/channels/${encodeURIComponent(x.uuid)}/icon" alt=""><div class="channel-copy"><strong class="channel-name-viewport" title="${esc(x.name)}"><span class="channel-name-track">${esc(x.name)}</span></strong><small>${esc(x.number?`频道 ${x.number}`:'频道号未设置')}</small></div></article>`).join(''):empty()}
async function loadEpg(){const modes={now:'正在播出',tonight:'今晚',tomorrow:'明天',all:'全部未来'},validModes=Object.keys(modes);if(!validModes.includes(state.epgMode))state.epgMode='now';view.innerHTML=`<div class="view-toolbar epg-toolbar"><div class="segmented epg-tabs">${Object.entries(modes).map(([key,label])=>`<button data-epg-mode="${key}" class="${key===state.epgMode?'active':''}">${label}</button>`).join('')}</div><details class="md-select epg-channel-select" id="epgChannel"><summary><span>频道</span><strong id="epgChannelLabel">全部频道</strong><i></i></summary><div class="md-select-menu" id="epgChannelMenu"></div></details></div><input class="search" id="epgSearch" placeholder="搜索节目、摘要或频道…"><section class="card epg-center-card"><div class="card-head"><h2 id="epgModeTitle"></h2><span class="badge" id="epgCount">—</span></div><div id="epgList"><div class="skeleton big"></div></div></section>`;let timer,channels=[];const renderChannels=()=>{const selected=channels.find(x=>x.uuid===state.epgChannel);$('#epgChannelLabel').textContent=selected?.name||'全部频道';$('#epgChannelMenu').innerHTML=[{uuid:'',name:'全部频道'},...channels].map(x=>`<button type="button" data-epg-channel="${esc(x.uuid)}" class="${x.uuid===state.epgChannel?'selected':''}"><span>${esc(x.name)}</span>${x.uuid===state.epgChannel?'<i>✓</i>':''}</button>`).join('');$('#epgChannelMenu').querySelectorAll('[data-epg-channel]').forEach(button=>button.onclick=async()=>{state.epgChannel=button.dataset.epgChannel;$('#epgChannel').removeAttribute('open');renderChannels();await fetchEpg()})};const fetchEpg=async()=>{const params=new URLSearchParams({mode:state.epgMode,q:$('#epgSearch').value});if(state.epgChannel)params.set('channel',state.epgChannel);$('#epgList').innerHTML='<div class="skeleton big"></div>';const data=await api('/api/epg?'+params);channels=data.channels||channels;if(state.epgChannel&&!channels.some(x=>x.uuid===state.epgChannel))state.epgChannel='';renderChannels();$('#epgModeTitle').textContent=modes[state.epgMode];$('#epgCount').textContent=`${data.total} 个节目`;$('#epgList').innerHTML=epgCenterRows(data.entries,data.serverTime);bindIconFallback($('#epgList'))};document.querySelectorAll('[data-epg-mode]').forEach(button=>button.onclick=async()=>{state.epgMode=button.dataset.epgMode;localStorage.setItem('epgMode',state.epgMode);document.querySelectorAll('[data-epg-mode]').forEach(item=>item.classList.toggle('active',item===button));await fetchEpg()});$('#epgSearch').oninput=()=>{clearTimeout(timer);timer=setTimeout(fetchEpg,250)};$('#epgList').onclick=e=>{const button=e.target.closest('.epg-record');if(button)openRecordDialog(button.dataset.event,button.dataset.channel)};await fetchEpg()}
function signalValue(v,scale){if(!v)return 0;if(Number(scale)===1)return Math.max(0,Math.min(100,v/65535*100));if(Number(scale)===2)return Math.max(0,Math.min(100,(v/1000+100)*1.25));return 0}
async function loadStatus(){const d=await api('/api/status');view.innerHTML=`<div class="resource-grid tuner-grid">${d.inputs.map(x=>{const sig=signalValue(x.signal,x.signal_scale);return`<article class="resource-card tuner-card"><div class="card-head"><span class="badge">${esc(x.kind)}</span><div class="signal">${[25,50,75,100].map(n=>`<i class="${sig>=n?'on':''}"></i>`).join('')}</div></div><h2>${esc(x.input_name)}</h2><p class="muted">${esc(x.stream_name||'当前空闲')}</p><div class="list"><div class="list-row"><span>信号</span><strong>${sig?sig.toFixed(0)+'%':'不可用'}</strong><span></span></div><div class="list-row"><span>SNR</span><strong>${x.snr_scale===2?(x.snr/1000).toFixed(1)+' dB':signalValue(x.snr,x.snr_scale).toFixed(0)+'%'}</strong><span></span></div><div class="list-row"><span>速率 / 订阅</span><strong>${(x.bps/1000000).toFixed(2)} Mbps / ${x.subscribers}</strong><span></span></div><div class="list-row"><span>错误</span><strong>${x.errors}</strong><span></span></div></div></article>`}).join('')||empty('尚未取得输入状态')}</div>`}
async function loadClients(){const data=await api('/api/clients'),clients=data.entries||[];if(data.error)throw Error(data.error);view.innerHTML=`<div class="client-grid">${clients.length?clients.map(client=>`<article class="client-card"><div class="client-head"><span class="client-symbol">${esc((client.type||'?')[0])}</span><div><strong>${esc(client.peer)}</strong><small>${client.peer_port?`端口 ${client.peer_port}`:'端口未知'}</small></div><span class="badge ${client.streaming?'live':''}">${client.streaming?'正在串流':'普通连接'}</span></div><div class="client-details"><div><span>协议</span><strong>${esc(client.type)}</strong></div><div><span>用户</span><strong>${esc(client.user)}</strong></div><div><span>连接时间</span><strong>${date(client.started)}</strong></div><div><span>持续时长</span><strong>${duration(Math.floor(Date.now()/1000)-client.started)}</strong></div></div><button class="tonal danger-action client-disconnect" data-client-disconnect="${client.id}" data-client-peer="${esc(client.peer)}">断开连接</button></article>`).join(''):empty('没有客户端连接')}</div>`;view.onclick=e=>{const button=e.target.closest('[data-client-disconnect]');if(!button)return;disconnectClientId=Number(button.dataset.clientDisconnect);$('#clientDisconnectCopy').textContent=`${button.dataset.clientPeer} 的连接将立即结束；正在播放的串流也会中断。`;$('#clientDisconnectError').textContent='';$('#clientDisconnectDialog').showModal()}}
function signalChart(samples,valueFor){if(samples.length<2)return empty('积累至少两次采样后显示趋势');const values=samples.map(valueFor),points=values.map((value,index)=>`${(index/(values.length-1)*100).toFixed(2)},${(32-Math.max(0,Math.min(100,value))*0.3).toFixed(2)}`).join(' ');return`<svg class="signal-chart" viewBox="0 0 100 36" preserveAspectRatio="none" aria-label="信号趋势"><path d="M0 32H100"/><polyline points="${points}"/></svg>`}
function diagnosticPanel(data){const samples=data.history||[],input=data.input,errors=samples.reduce((total,item)=>total+Number(item.error_delta||0),0);return`<div class="diagnostic-grid"><div><span>信号趋势</span>${signalChart(samples,item=>signalValue(item.signal,item.signal_scale))}</div><div><span>SNR 趋势</span>${signalChart(samples,item=>signalValue(item.snr,item.snr_scale))}</div></div><div class="diagnostic-summary"><span>内存采样 ${samples.length} / ${data.limit}</span><span>新增错误 ${errors}</span><span>当前 ${input.subscribers?'正在使用':'空闲'}</span></div>`}
async function loadStatus(){const d=await api('/api/status'),healthNames={idle:'空闲',good:'良好',weak:'信号偏弱',error:'发现新错误'};view.innerHTML=`<div class="resource-grid tuner-grid">${d.inputs.map(x=>{const sig=signalValue(x.signal,x.signal_scale);return`<article class="resource-card tuner-card" data-input-card="${esc(x.input_uuid)}"><div class="card-head"><span class="badge health-${esc(x.health)}">${esc(healthNames[x.health]||x.kind)}</span><div class="signal">${[25,50,75,100].map(n=>`<i class="${sig>=n?'on':''}"></i>`).join('')}</div></div><h2>${esc(x.input_name)}</h2><p class="muted">${esc(x.stream_name||'当前空闲')}</p><div class="list"><div class="list-row"><span>信号</span><strong>${sig?sig.toFixed(0)+'%':'不可用'}</strong><span></span></div><div class="list-row"><span>SNR</span><strong>${x.snr_scale===2?(x.snr/1000).toFixed(1)+' dB':signalValue(x.snr,x.snr_scale).toFixed(0)+'%'}</strong><span></span></div><div class="list-row"><span>速率 / 订阅</span><strong>${(x.bps/1000000).toFixed(2)} Mbps / ${x.subscribers}</strong><span></span></div><div class="list-row"><span>错误</span><strong>${x.errors}${x.error_delta?`（新增 ${x.error_delta}）`:''}</strong><span></span></div></div><button class="tonal diagnostic-toggle" data-diagnose="${esc(x.input_uuid)}">查看趋势</button><div class="diagnostic-panel hidden" data-diagnostic></div></article>`}).join('')||empty('尚未取得输入状态')}</div>`;view.onclick=async e=>{const button=e.target.closest('[data-diagnose]');if(!button)return;const card=button.closest('[data-input-card]'),panel=card.querySelector('[data-diagnostic]');if(!panel.classList.contains('hidden')){panel.classList.add('hidden');button.textContent='查看趋势';return}button.disabled=true;try{panel.innerHTML=diagnosticPanel(await api('/api/status/diagnostics?input='+encodeURIComponent(button.dataset.diagnose)));panel.classList.remove('hidden');button.textContent='收起趋势'}catch(err){panel.innerHTML=`<p class="form-error">${esc(err.message)}</p>`;panel.classList.remove('hidden')}finally{button.disabled=false}}}
async function getResources(){if(!state.resources)state.resources=(await api('/api/resources')).resources;return state.resources}
const statusText=v=>{v=localized(v);return {"Scheduled for recording":"已安排录像","Recording":"正在录像","Completed OK":"录像完成","Completed with errors":"录像完成（有错误）","Missed":"已错过","Invalid target":"目标无效","Time missed":"已错过时间","User access error":"用户权限错误","File removed":"文件已移除","Completed":"录像完成","Failed":"录像失败"}[v]||v||'未知'};
function recordingIcon(x){const uuid=x.channel_uuid||x.channelUuid||x.channel;return uuid?`<img class="recording-avatar channel-icon epg-icon" data-fallback src="/api/channels/${encodeURIComponent(uuid)}/icon" alt="">`:`<div class="recording-avatar channel-icon tv-fallback">${tvIcon()}</div>`}
const dvrButton=(action,label,x,danger=false)=>`<button class="tonal dvr-action ${danger?'danger-action':''}" data-action="${action}" data-uuid="${esc(x.uuid)}" data-title="${esc(localized(x.title||x.disp_title||x.name)||'录像项目')}">${label}</button>`;
function recordingRows(items,section){if(section==='autorecs'||section==='timerecs')return items.map(x=>`<article class="list-row recording-row"><div class="recording-avatar tv-fallback">${tvIcon()}</div><div class="recording-copy"><strong>${esc(localized(x.title||x.name)||'未命名录像规则')}</strong><small>${esc(localized(x.channel)||'全部频道')} · ${esc(x.start||'任意时段')}${section==='timerecs'?` - ${esc(x.stop||'')}`:''}</small><small>${esc(x.comment||recordingSections[section])}</small></div><div class="recording-actions"><span class="badge ${x.enabled!==false?'scheduled':''}">${x.enabled!==false?'已启用':'已停用'}</span>${dvrButton(section==='autorecs'?'delete_autorec':'delete_timerec','删除规则',x,true)}</div></article>`).join('');return items.map(x=>{const [main,eng]=titlePair(x.title||x.disp_title);const [day,clock]=fullDate(x.start),status=String(x.status||x.sched_status),scheduled=section==='upcoming'&&status.includes('Scheduled'),running=section==='upcoming'&&status.toLowerCase().includes('recording');let actions='';if(section==='upcoming')actions=(running?dvrButton('stop','停止录像',x,true):scheduled?dvrButton('cancel','取消安排',x,true):'')+dvrButton('previously_recorded','标为已录',x);if(section==='finished')actions=`<a class="tonal download-recording" href="/api/dvr/download/${encodeURIComponent(x.uuid)}">下载</a>`+dvrButton('rerecord_finished','重新录像',x)+dvrButton('move_failed','标为失败',x)+dvrButton('remove','移除文件',x,true);if(section==='failed')actions=dvrButton('rerecord_failed','重新录像',x)+dvrButton('move_finished','标为完成',x);return`<article class="list-row recording-row">${recordingIcon(x)}<div class="recording-copy"><strong>${esc(main||'无标题')}</strong>${eng?`<small>${esc(eng)}</small>`:''}<small>${esc(localized(x.channelname)||'频道未知')}</small><small>${day}　${clock}</small></div><div class="recording-actions"><span class="badge ${scheduled?'scheduled':''}">${esc(statusText(status))}</span>${actions}</div></article>`}).join('')}
const recordingSectionsLegacy={upcoming:'待录像',finished:'已完成',failed:'失败',removed:'已移除',autorecs:'自动录像',timerecs:'手动定时'};
async function loadRecordings(){view.innerHTML=`<div class="view-toolbar recording-toolbar"><div class="segmented dvr-tabs">${Object.entries(recordingSections).map(([key,label])=>`<button data-dvr-section="${key}" class="${key===state.recordingSection?'active':''}">${label}</button>`).join('')}</div><button class="primary add-recording" id="addRecording">${state.recordingSection==='autorecs'?'新建自动录像':state.recordingSection==='timerecs'?'新建定时规则':'安排录像'}</button></div><section class="card recording-card"><div class="card-head"><h2>${recordingSections[state.recordingSection]}</h2><span class="badge" id="recordingCount">—</span></div><div class="list" id="recordingRows"><div class="skeleton big"></div></div><div class="empty hidden" id="recordingEmpty">此分类暂无录像</div></section>`;const render=async()=>{const data=await api('/api/dvr/library?section='+state.recordingSection);$('#recordingCount').textContent=`${data.total} 项`;$('#recordingRows').innerHTML=recordingRows(data.entries,state.recordingSection);$('#recordingEmpty').classList.toggle('hidden',data.entries.length>0);bindIconFallback($('#recordingRows'));document.querySelectorAll('[data-dvr-section]').forEach(button=>button.classList.toggle('active',button.dataset.dvrSection===state.recordingSection))};document.querySelectorAll('[data-dvr-section]').forEach(button=>button.onclick=async()=>{state.recordingSection=button.dataset.dvrSection;await loadRecordings()});$('#addRecording').onclick=()=>state.recordingSection==='autorecs'?openRecordRule('autorec'):state.recordingSection==='timerecs'?openRecordRule('timerec'):openRecordDialog();$('#recordingRows').onclick=e=>{const button=e.target.closest('.dvr-action');if(button)openDvrAction(button.dataset.action,button.dataset.uuid,button.dataset.title)};await render()}
function renderRecordOptions(data){scheduleState.events=data.events;scheduleState.profiles=data.profiles;if(!data.profiles.some(x=>x.uuid===scheduleState.configUuid))scheduleState.configUuid=data.profiles[0]?.uuid||'';$('#recordProfiles').innerHTML=data.profiles.length?`<small>录像配置</small><div class="segmented">${data.profiles.map(x=>`<button type="button" data-profile="${esc(x.uuid)}" class="${x.uuid===scheduleState.configUuid?'active':''}">${esc(x.name)}</button>`).join('')}</div>`:`<p class="form-error">Tvheadend 没有可用的录像配置</p>`;$('#recordEvents').innerHTML=data.events.length?data.events.map(x=>`<button type="button" class="record-event ${String(x.event_id)===scheduleState.eventId?'selected':''}" data-event="${esc(x.event_id)}"><strong>${esc(localized(x.title)||'无标题')}</strong><small>${esc(x.channel_name)} · ${epgRange(x.start,x.stop)}</small></button>`).join(''):empty('没有匹配的未来节目');$('#recordProfiles').querySelectorAll('[data-profile]').forEach(button=>button.onclick=()=>{scheduleState.configUuid=button.dataset.profile;renderRecordOptions(data)});$('#recordEvents').querySelectorAll('[data-event]').forEach(button=>button.onclick=()=>{scheduleState.eventId=button.dataset.event;renderRecordOptions(data)});$('#recordSubmit').disabled=!(scheduleState.eventId&&scheduleState.configUuid)}
async function fetchRecordOptions(query=''){try{const data=await api('/api/dvr/options?q='+encodeURIComponent(query));scheduleState.channels=data.channels||[];renderRecordOptions(data);return data}catch(err){$('#recordError').textContent=err.message}}
async function openRecordDialog(){scheduleState.eventId='';scheduleState.configUuid='';$('#recordSearch').value='';$('#recordError').textContent='';$('#recordEvents').innerHTML='<div class="skeleton big"></div>';const dialog=$('#recordDialog');if(!dialog.open)dialog.showModal();dialog.focus({preventScroll:true});await fetchRecordOptions()}
