$('#nav').onclick=e=>{const b=e.target.closest('button[data-view]');if(b){navigate(b.dataset.view);requestAnimationFrame(()=>b.scrollIntoView({behavior:reducedMotion()?'auto':'smooth',block:'nearest',inline:'center'}))}};$('#menuBtn').onclick=()=>$('#rail').classList.toggle('collapsed');let refreshInFlight=false;$('#refreshBtn').onclick=async()=>{if(refreshInFlight)return;const button=$('#refreshBtn');stopViewAnimation();refreshInFlight=true;button.disabled=true;button.classList.add('refreshing');button.setAttribute('aria-busy','true');try{await api('/api/sync',{method:'POST'});state.resources=null;await delay(420);await navigate(state.view,{quiet:true,refresh:true})}catch(err){showNotice(err.message)}finally{await finishRefreshCycle(button);refreshInFlight=false;button.disabled=false;button.classList.remove('refreshing');button.removeAttribute('aria-busy')}};matchMedia('(prefers-color-scheme:dark)').addEventListener('change',applyTheme);
